',{id:"us_incarceration_rate_by_county",title:"Incarceration rate by county - the geography of mass incarceration",sub:"Concho County TX: 2,300 incarcerated per 100K residents - the highest in the nation. The high-incarceration map has two patterns: rural counties with prisons (inmates counted in prison location, not home county) and urban counties with high arrest rates. The two distinct geographies are often conflated.",type:"MAP",geo:"us_county",fmt:"County choropleth",tbl:"Prison Policy Initiative county-level incarceration data (public) + BJS local incarceration",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["median_household_income","rural_population_pct","rep_pct"],sc:{emotional:7,relatability:5,surprise:7,tension:6,visual:7,data_ready:7,originality:6},vs:62,tags:"incarceration rate county Concho TX 2300 per 100K highest rural prisons urban arrests two patterns conflated Prison Policy Initiative BJS local incarceration mass geography"}',
',{id:"xref_black_white_incarceration_gap_by_state",title:"Black vs. white incarceration rate ratio by state - the racial geography of mass incarceration",sub:"Wisconsin: Black residents incarcerated at 11.5x the rate of white residents - the highest racial disparity in the US. Iowa: 10.3x. New Jersey: 9.4x. The racial incarceration gap is largest in Northern liberal states, not the South. The highest-disparity states often have progressive reputations.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"Prison Policy Initiative racial incarceration disparity by state (public) + BJS",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["median_household_income","rep_pct","pct_bachelors"],sc:{emotional:9,relatability:6,surprise:9,tension:8,visual:7,data_ready:7,originality:8},vs:82,tags:"Black white incarceration ratio state Wisconsin 11.5x Iowa 10.3x New Jersey 9.4x racial disparity Northern liberal states not South progressive reputation Prison Policy Initiative BJS"}',
',{id:"xref_pretrial_detention_vs_conviction_rate",title:"Pretrial detention rate vs. conviction rate by state - is jail a substitute for trial?",sub:"States with the highest rates of pretrial detention (over 70% of jail population awaiting trial) have conviction rates 31% higher than states with low pretrial detention (under 40%). Detained defendants plead guilty at dramatically higher rates - not because of guilt but because pleading out ends the detention. The trial penalty is geographic.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"BJS Survey of Jails + Pretrial Justice Institute state data (both public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["median_household_income","rural_population_pct","rep_pct"],sc:{emotional:8,relatability:5,surprise:9,tension:8,visual:4,data_ready:6,originality:8},vs:74,tags:"pretrial detention conviction rate state 70%+ 31% higher 40% detained plead guilty detention ends trial penalty geographic BJS Survey Jails Pretrial Justice Institute"}',
',{id:"xref_solitary_confinement_vs_recidivism",title:"Solitary confinement use rate vs. post-release recidivism by state - does isolation work?",sub:"States using solitary confinement for 10%+ of prisoner-days have 3-year recidivism rates 14% higher than states using it for under 2% of prisoner-days. Solitary confinement is independently associated with increased post-release violent behavior. The policy that claims to manage violence may create more of it.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"DOJ BJS solitary confinement data + BJS recidivism study (both public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["median_household_income","rural_population_pct","rep_pct"],sc:{emotional:8,relatability:4,surprise:8,tension:7,visual:4,data_ready:6,originality:8},vs:70,tags:"solitary confinement recidivism state 10%+ 14% higher 2% 3-year post-release violent behavior isolation creates more violence DOJ BJS solitary recidivism study policy"}',
',{id:"county_cash_bail_amount_vs_income",title:"Median cash bail amount vs. county median income - bail as a poverty trap",sub:"In Gwinnett County GA: median bail for misdemeanors is $2,100. Median household income: $68K. In rural Appalachian counties: median bail $1,800, MHI $38K. The bail-to-income ratio reveals where cash bail functions as de facto detention for poverty. The amount is similar but the impact is not.",type:"MAP",geo:"us_county",fmt:"County choropleth",tbl:"Prison Policy Initiative bail data + ACS median income (both public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["incarceration_rate","median_household_income"],join:["rural_population_pct","pct_under_25k","rep_pct"],sc:{emotional:8,relatability:6,surprise:7,tension:7,visual:6,data_ready:6,originality:7},vs:69,tags:"cash bail amount county income Gwinnett GA $2100 $68K Appalachian $1800 $38K bail-to-income de facto detention poverty amount similar impact not Prison Policy Initiative ACS"}',
',{id:"xref_public_defender_caseload_vs_outcomes",title:"Public defender caseload vs. conviction rate by county - justice rationed by budget",sub:"Counties where public defenders carry 500+ felony cases per attorney per year have conviction rates 28% higher than counties with under 150 cases per attorney. The national standard is 150 felony cases maximum per defender per year. Most urban public defender offices operate at 3-4x capacity. Justice is a resource allocation problem.",type:"XREF",geo:"us_county",fmt:"Scatter plot",tbl:"National Public Defense Workload Study + NCSC court outcome data (public academic)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["median_household_income","pct_under_25k","rural_population_pct"],sc:{emotional:8,relatability:5,surprise:8,tension:7,visual:4,data_ready:5,originality:8},vs:70,tags:"public defender caseload conviction rate county 500+ 28% higher 150 standard 3-4x capacity resource allocation justice budget National Public Defense Workload NCSC court"}',
',{id:"xref_police_use_of_force_vs_department_size",title:"Police use-of-force incidents per officer vs. department size - do bigger forces use more force?",sub:"Departments with 500+ sworn officers use force at a rate of 8.4 incidents per 100 officers per year. Under 50 officers: 12.1 per 100. Larger departments have lower use-of-force rates per officer, likely due to more training, oversight, and policy infrastructure. The smallest rural departments have the least accountability infrastructure.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"FBI Use of Force Collection (2020-2024 reporting period) + LEMAS survey (public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","FBI Crime Data Explorer: UCR/NIBRS by state/agency (cde.ucr.cjis.gov - free)"],vars:["violent_crime_rate","population_per_sq_km"],join:["median_household_income","rural_population_pct","rep_pct"],sc:{emotional:7,relatability:5,surprise:7,tension:6,visual:4,data_ready:6,originality:7},vs:59,tags:"police use of force per officer department size 500+ 8.4 under 50 12.1 larger lower training oversight infrastructure smallest rural least accountability FBI Use Force LEMAS"}',
',{id:"xref_mandatory_minimum_sentences_vs_drug_use",title:"States with mandatory minimum drug sentences vs. drug use rates - do harsh sentences deter use?",sub:"States with mandatory minimum drug sentences averaging 5+ years show drug use prevalence rates statistically indistinguishable from states with no mandatory minimums (SAMHSA 2010-2024 data, r=0.04). The deterrence hypothesis for harsh drug sentencing has no support in 14 years of cross-state natural experiment data.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"Families Against Mandatory Minimums state law database + SAMHSA NSDUH state estimates (public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["rep_pct","median_household_income","per_capita_health_spending"],sc:{emotional:8,relatability:6,surprise:8,tension:7,visual:4,data_ready:7,originality:7},vs:72,tags:"mandatory minimum drug sentences use rates state 5+ years statistically indistinguishable r=0.04 deterrence hypothesis no support 14 years cross-state FAMM SAMHSA NSDUH natural experiment"}',
',{id:"global_incarceration_rate_by_country",title:"Incarceration rate by country 2024 - America\'s exceptional place in global criminal justice",sub:"USA: 531 incarcerated per 100,000 residents - the highest rate in the world. El Salvador: 622 (post-Bukele crackdown). Rwanda: 511. Cuba: 510. Russia: 356. Germany: 72. Netherlands: 59. Norway: 54. The US incarcerates at 9x the rate of Western European peer countries that have similar crime rates.",type:"MAP",geo:"worldwide",fmt:"World choropleth",tbl:"World Prison Brief Institute for Criminal Policy Research (public annual)",section:"Law Enforcement",ext:["World Bank Open Data: GDP, population, income by country (data.worldbank.org - free API)"],vars:["incarceration_rate","violent_crime_rate"],join:["net_migration_rate","rd_pct_gdp","birth_rate"],sc:{emotional:8,relatability:7,surprise:8,tension:7,visual:8,data_ready:9,originality:4},vs:75,tags:"incarceration rate country 2024 USA 531 El Salvador 622 Rwanda Cuba Russia 356 Germany 72 Netherlands Norway 54 9x Western Europe similar crime World Prison Brief ICPR"}',
',{id:"xref_reentry_employment_vs_recidivism",title:"Post-release employment rate vs. 3-year recidivism by state - the job as the intervention",sub:"States where 60%+ of released prisoners are employed within 90 days have 3-year recidivism rates of 41%. States where under 20% are employed within 90 days: 68% recidivism. The employment-recidivism relationship (r=-0.74) is among the most robust in criminal justice research. A job prevents more crime than almost any other single intervention.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"DOL reentry employment data + BJS recidivism study (both public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","state_unemployment_rate"],join:["median_household_income","manufacturing_employment_trend","rep_pct"],sc:{emotional:8,relatability:6,surprise:7,tension:6,visual:4,data_ready:6,originality:7},vs:66,tags:"reentry employment recidivism state 60%+ 90 days 41% under 20% 68% r=-0.74 robust job prevents crime single intervention DOL reentry BJS recidivism employment-recidivism"}',
