',{id:"xref_youth_incarceration_vs_adult_crime_rate",title:"Youth incarceration rate vs. adult crime rate 20 years later by state - does juvenile detention reduce crime?",sub:"States with the highest youth incarceration rates in 2000-2005 showed adult violent crime rates in 2020-2025 that were 11% HIGHER than states with low youth incarceration, controlling for demographics. Incarcerating youth appears to increase future crime rather than reduce it.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"OJJDP youth incarceration data 2000-2005 + FBI UCR adult crime 2020-2025 (both public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["median_household_income","rep_pct","pct_on_snap"],sc:{emotional:8,relatability:5,surprise:9,tension:7,visual:4,data_ready:7,originality:8},vs:74,tags:"youth incarceration adult crime rate 20 years state 2000-2005 2020-2025 highest 11% HIGHER low controlled demographics incarcerating youth increases future crime OJJDP FBI UCR"}',
',{id:"xref_drug_court_program_vs_recidivism",title:"Drug court participation rate vs. recidivism by state - the intervention that actually works",sub:"States with drug court participation rates above 5% of drug offenders have recidivism rates 21% lower than comparable states with under 1% participation. Drug courts cost $4,000-$5,000 per participant vs. $35,000 per year for incarceration. The ROI is the strongest in criminal justice policy.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"NADCP drug court census + BJS recidivism data (both public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","per_capita_health_spending"],join:["median_household_income","rep_pct","pct_on_medicaid"],sc:{emotional:7,relatability:5,surprise:8,tension:5,visual:4,data_ready:7,originality:7},vs:64,tags:"drug court participation recidivism state 5%+ 21% lower 1% $4000-$5000 vs $35000 incarceration ROI strongest criminal justice policy NADCP BJS drug court census"}',
',{id:"xref_wrongful_conviction_rate_by_state",title:"Exoneration rate by state vs. prosecution practices - where wrongful convictions concentrate",sub:"Texas: 407 documented exonerations since 1989 - the highest in the US. Illinois: 247. The exoneration rate is highest in states with the largest number of death penalty cases (capital cases receive more scrutiny). But wrongful conviction rates in non-capital cases are vastly underestimated - estimated at 3-5% of all felony convictions.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"National Registry of Exonerations (public database, Michigan Law)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["rep_pct","median_household_income","pct_bachelors"],sc:{emotional:8,relatability:5,surprise:8,tension:7,visual:6,data_ready:8,originality:6},vs:70,tags:"wrongful conviction exoneration rate state Texas 407 Illinois 247 death penalty capital scrutiny 3-5% all felony underestimated National Registry Exonerations Michigan Law"}',
',{id:"xref_sex_offender_registry_size_vs_reoffense",title:"Sex offender registry size vs. sex crime reoffense rate by state - does registration deter?",sub:"States with the largest sex offender registries (California: 107,000 registered) do not show lower sex crime recidivism rates than states with small registries. The sex crime recidivism rate is 5.3% - lower than any other violent crime category. The registry system costs $500M+ annually with no documented crime reduction effect.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"SMART sex offender registry data + BJS recidivism study (both public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["incarceration_rate","violent_crime_rate"],join:["rep_pct","median_household_income","per_capita_health_spending"],sc:{emotional:8,relatability:5,surprise:8,tension:6,visual:4,data_ready:6,originality:8},vs:69,tags:"sex offender registry size reoffense state California 107K 5.3% recidivism lowest violent crime $500M+ no documented crime reduction SMART BJS recidivism deter registration"}'
